import { GD } from './constants'

export async function getProvinceByCoordinates(longitude, latitude) {
  const url = `https://restapi.amap.com/v3/geocode/regeo?key=${GD}&location=${longitude},${latitude}`

  try {
    const response = await fetch(url)
    const data = await response.json()

    if (data.status === '1' && data.regeocode) {
      return data
    }
    return '未知'
  } catch (error) {
    console.error('获取地理位置失败:', error)
    return '未知'
  }
}

export async function getProvince(longitude, latitude) {
  const url = `https://restapi.amap.com/v3/geocode/regeo?key=${GD}&location=${longitude},${latitude}`

  try {
    const response = await fetch(url)
    const data = await response.json()

    if (data.status === '1' && data.regeocode) {
      return data.regeocode.addressComponent.province
    }
    return '未知'
  } catch (error) {
    console.error('获取地理位置失败:', error)
    return '未知'
  }
}
